  "productos.msg_importacion_resultado": { es: "Importación terminada: {importados} producto(s) importado(s), {omitidos} omitido(s) por datos inválidos.", en: "Import finished: {importados} product(s) imported, {omitidos} skipped due to invalid data.", pt: "Importação concluída: {importados} produto(s) importado(s), {omitidos} ignorado(s) por dados inválidos.", fr: "Importation terminée : {importados} produit(s) importé(s), {omitidos} ignoré(s) pour données invalides.", de: "Import abgeschlossen: {importados} Produkt(e) importiert, {omitidos} wegen ungültiger Daten übersprungen.", zh: "导入完成：已导入 {importados} 个产品，因数据无效跳过 {omitidos} 个。" },

