  "traspasos.confirmar_eliminar_ubicacion": { es: "¿Eliminar esta ubicación?", en: "Delete this location?", pt: "Excluir este local?", fr: "Supprimer cet emplacement ?", de: "Diesen Standort löschen?", zh: "确定要删除此库位吗？" },
