  "traspasos.msg_origen_destino_iguales": { es: "El origen y el destino no pueden ser el mismo.", en: "The origin and destination can't be the same.", pt: "A origem e o destino não podem ser iguais.", fr: "L'origine et la destination ne peuvent pas être identiques.", de: "Ursprung und Ziel dürfen nicht gleich sein.", zh: "起点和目的地不能相同。" },
