  "traspasos.sin_ubicaciones": { es: "Todavía no tienes ubicaciones. Agrega la primera arriba.", en: "You don't have any locations yet. Add the first one above.", pt: "Você ainda não tem locais. Adicione o primeiro acima.", fr: "Vous n'avez pas encore d'emplacements. Ajoutez le premier ci-dessus.", de: "Du hast noch keine Standorte. Füge oben den ersten hinzu.", zh: "您还没有库位，请在上方添加第一个。" },
